nsigned long desc,\n\t\t\t       struct resource *res)\n{\n\treturn find_next_res(&iomem_resource, start, end, flags, desc, res);\n}\n\nstatic int walk_res_desc(struct resource *parent, resource_size_t start,\n\t\t\t resource_size_t end, unsigned long flags,\n\t\t\t unsigned long desc, void *arg,\n\t\t\t int (*func)(struct resource *, void *))\n{\n\tstruct resource res;\n\tint ret = -EINVAL;\n\n\twhile (start < end &&\n\t       !find_next_res(parent, start, end, flags, desc, &res)) {\n\t\tret = (*func)(&res, arg);\n\t\tif (ret)\n\t\t\tbreak;\n\n\t\tstart = res.end + 1;\n\t}\n\n\treturn ret;\n}\n\nstatic int __walk_iomem_res_desc(resource_size_t start, resource_size_t end,\n\t\t\t\t unsigned long flags, unsigned long desc,\n\t\t\t\t void *arg,\n\t\t\t\t int (*func)(struct resource *, void *))\n{\n\treturn walk_res_desc(&iomem_resource, start, end, flags, desc, arg, func);\n}\n\n\n/**\n * walk_iomem_res_desc - Walks through iomem resources and calls func()\n *\t\t\t with matching resource ranges.\n * *\n * @desc: I/O resource descriptor. Use IORES_DESC_NONE to skip @desc check.\n * @flags: I/O resource flags\n * @start: start addr\n * @end: end addr\n * @arg: function argument for the callback @func\n * @func: callback function that is called for each qualifying resource area\n *\n * All the memory ranges which overlap start,end and also match flags and\n * desc are valid candidates.\n *\n * NOTE: For a new descriptor search, define a new IORES_DESC in\n * <linux/ioport.h> and set it in 'desc' of a target resource entry.\n */\nint walk_iomem_res_desc(unsigned long desc, unsigned long flags, u64 start,\n\t\tu64 end, void *arg, int (*func)(struct resource *, void *))\n{\n\treturn __walk_iomem_res_desc(start, end, flags, desc, arg, func);\n}\nEXPORT_SYMBOL_GPL(walk_iomem_res_desc);\n\n/*\n * In support of device drivers claiming Soft Reserved resources, walk the Soft\n * Reserved resource deferral tree.\n */\nint walk_soft_reserve_res(u64 start, u64 end, void *arg,\n\t\t\t  int (*func)(struct resource *, void *))\n{\n\treturn walk_res_desc(&soft_reserve_resource, start, end, IORESOURCE_MEM,\n\t\t\t     IORES_DESC_SOFT_RESERVED, arg, func);\n}\nEXPORT_SYMBOL_GPL(walk_soft_reserve_res);\n\n/*\n * This function calls the @func callback against all memory ranges of type\n * System RAM which are marked as IORESOURCE_SYSTEM_RAM and IORESOUCE_BUSY.\n * Now, this function is only for System RAM, it deals with full ranges and\n * not PFNs. If resources are not PFN-aligned, dealing with PFNs can truncate\n * ranges.\n */\nint walk_system_ram_res(u64 start, u64 end, void *arg,\n\t\t\tint (*func)(struct resource *, void *))\n{\n\tunsigned long flags = IORESOURCE_SYSTEM_RAM | IORESOURCE_BUSY;\n\n\treturn __walk_iomem_res_desc(start, end, flags, IORES_DESC_NONE, arg,\n\t\t\t\t     func);\n}\n\n/*\n * This function, being a variant of walk_system_ram_res(), calls the @func\n * callback against all memory ranges of type System RAM which are marked as\n * IORESOURCE_SYSTEM_RAM and IORESOUCE_BUSY in reversed order, i.e., from\n * higher to lower.\n */\nint walk_system_ram_res_rev(u64 start, u64 end, void *arg,\n\t\t\t\tint (*func)(struct resource *, void *))\n{\n\tstruct resource res, *rams;\n\tint rams_size = 16, i;\n\tunsigned long flags;\n\tint ret = -1;\n\n\t/* create a list */\n\trams = kvzalloc_objs(struct resource, rams_size);\n\tif (!rams)\n\t\treturn ret;\n\n\tflags = IORESOURCE_SYSTEM_RAM | IORESOURCE_BUSY;\n\ti = 0;\n\twhile ((start < end) &&\n\t\t(!find_next_iomem_res(start, end, flags, IORES_DESC_NONE, &res))) {\n\t\tif (i >= rams_size) {\n\t\t\t/* re-alloc */\n\t\t\tstruct resource *rams_new;\n\n\t\t\trams_new = kvrealloc(rams, (rams_size + 16) * sizeof(struct resource),\n\t\t\t\t\t     GFP_KERNEL);\n\t\t\tif (!rams_new)\n\t\t\t\tgoto out;\n\n\t\t\trams = rams_new;\n\t\t\trams_size += 16;\n\t\t}\n\n\t\trams[i++] = res;\n\t\tstart = res.end + 1;\n\t}\n\n\t/* go reverse */\n\tfor (i--; i >= 0; i--) {\n\t\tret = (*func)(&rams[i], arg);\n\t\tif (ret)\n\t\t\tbreak;\n\t}\n\nout:\n\tkvfree(rams);\n\treturn ret;\n}\n\n/*\n * This function calls the @func callback against all memory ranges, which\n * are ranges marked as IORESOURCE_MEM and IORESOUCE_BUSY.\n */\nint walk_mem_res(u64 start, u64 end, void *arg,\n\t\t int (*func)(struct resource *, void *))\n{\n\tunsigned long flags = IORESOURCE_MEM | IORESOURCE_BUSY;\n\n\treturn __walk_iomem_res_desc(start, end, flags, IORES_DESC_NONE, arg,\n\t\t\t\t     func);\n}\n\n/*\n * This function calls the @func callback against all memory ranges of type\n * System RAM which are marked as IORESOURCE_SYSTEM_RAM and IORESOUCE_BUSY.\n * It is to be used only for System RAM.\n */\nint walk_system_ram_range(unsigned long start_pfn, unsigned long nr_pages,\n\t\t\t  void *arg, int (*func)(unsigned long, unsigned long, void *))\n{\n\tresource_size_t start, end;\n\tunsigned long flags;\n\tstruct resource res;\n\tunsigned long pfn, end_pfn;\n\tint ret = -EINVAL;\n\n\tstart = (u64) start_pfn << PAGE_SHIFT;\n\tend = ((u64)(start_pfn + nr_pages) << PAGE_SHIFT) - 1;\n\n... [Diff truncated. Dropped 1235 lines] ...\n\n\t\tif (x < MAXRESERVE) {\n\t\t\tstruct resource *res = reserve + x;\n\n\t\t\t/*\n\t\t\t * If the region starts below 0x10000, we assume it's\n\t\t\t * I/O port space; otherwise assume it's memory.\n\t\t\t */\n\t\t\tif (io_start < 0x10000) {\n\t\t\t\t*res = DEFINE_RES_IO_NAMED(io_start, io_num, \"reserved\");\n\t\t\t\tparent = &ioport_resource;\n\t\t\t} else {\n\t\t\t\t*res = DEFINE_RES_MEM_NAMED(io_start, io_num, \"reserved\");\n\t\t\t\tparent = &iomem_resource;\n\t\t\t}\n\t\t\tres->flags |= IORESOURCE_BUSY;\n\t\t\tif (request_resource(parent, res) == 0)\n\t\t\t\treserved = x+1;\n\t\t}\n\t}\n\treturn 1;\n}\n__setup(\"reserve=\", reserve_setup);\n\n/*\n * Check if the requested addr and size spans more than any slot in the\n * iomem resource tree.\n */\nint iomem_map_sanity_check(resource_size_t addr, unsigned long size)\n{\n\tresource_size_t end = addr + size - 1;\n\tstruct resource *p;\n\tint err = 0;\n\n\tread_lock(&resource_lock);\n\tfor_each_resource(&iomem_resource, p, false) {\n\t\t/*\n\t\t * We can probably skip the resources without\n\t\t * IORESOURCE_IO attribute?\n\t\t */\n\t\tif (p->start > end)\n\t\t\tcontinue;\n\t\tif (p->end < addr)\n\t\t\tcontinue;\n\t\tif (PFN_DOWN(p->start) <= PFN_DOWN(addr) &&\n\t\t    PFN_DOWN(p->end) >= PFN_DOWN(end))\n\t\t\tcontinue;\n\t\t/*\n\t\t * if a resource is \"BUSY\", it's not a hardware resource\n\t\t * but a driver mapping of such a resource; we don't want\n\t\t * to warn for those; some drivers legitimately map only\n\t\t * partial hardware resources. (example: vesafb)\n\t\t */\n\t\tif (p->flags & IORESOURCE_BUSY)\n\t\t\tcontinue;\n\n\t\tpr_warn(\"resource sanity check: requesting [mem %pa-%pa], which spans more than %s %pR\\n\",\n\t\t\t&addr, &end, p->name, p);\n\t\terr = -1;\n\t\tbreak;\n\t}\n\tread_unlock(&resource_lock);\n\n\treturn err;\n}\n\n#ifdef CONFIG_STRICT_DEVMEM\nstatic int strict_iomem_checks = 1;\n#else\nstatic int strict_iomem_checks;\n#endif\n\n/*\n * Check if an address is exclusive to the kernel and must not be mapped to\n * user space, for example, via /dev/mem.\n *\n * Returns true if exclusive to the kernel, otherwise returns false.\n */\nbool resource_is_exclusive(struct resource *root, u64 addr, resource_size_t size)\n{\n\tconst unsigned int exclusive_system_ram = IORESOURCE_SYSTEM_RAM |\n\t\t\t\t\t\t  IORESOURCE_EXCLUSIVE;\n\tbool skip_children = false, err = false;\n\tstruct resource *p;\n\n\tread_lock(&resource_lock);\n\tfor_each_resource(root, p, skip_children) {\n\t\tif (p->start >= addr + size)\n\t\t\tbreak;\n\t\tif (p->end < addr) {\n\t\t\tskip_children = true;\n\t\t\tcontinue;\n\t\t}\n\t\tskip_children = false;\n\n\t\t/*\n\t\t * IORESOURCE_SYSTEM_RAM resources are exclusive if\n\t\t * IORESOURCE_EXCLUSIVE is set, even if they\n\t\t * are not busy and even if \"iomem=relaxed\" is set. The\n\t\t * responsible driver dynamically adds/removes system RAM